import{c as a,Q as t,j as i,m as s}from"./chunks/framework.BBA2dIOt.js";const u=JSON.parse(`{"title":"Ember","titleTemplate":"Self-hosted RSS reader with on-device AI summaries","description":"","frontmatter":{"layout":"home","title":"Ember","titleTemplate":"Self-hosted RSS reader with on-device AI summaries","hero":{"name":"Ember","text":"A reader for people who read.","tagline":"Self-hosted RSS aggregation with an optional on-device LLM and a paper-and-ink interface. One Go binary, one container, one tab.","image":{"light":"/screenshots/hero-2-threepane-summary-dark.png","dark":"/screenshots/hero-2-threepane-summary-light.png","alt":"Ember three-pane reader with AI summary card"},"actions":[{"theme":"brand","text":"Get started","link":"/getting-started"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/brandonhon/ember"}]},"features":[{"icon":"📰","title":"Three-pane reader","details":"Sidebar of feeds and folders, the article list, and a focused reader. Keyboard navigation (j/k/r/m/s/?), drag-to-reorder."},{"icon":"🧠","title":"Local AI summaries","details":"Optional Ollama integration produces a paragraph + bullet summary for each article. Pull, swap, and tune models from the admin UI. Strips newsletter / podcast promos from the body."},{"icon":"🔎","title":"FTS5 full-text search","details":"SQLite's FTS5 powers a dedicated search view + saved searches surfaced in the sidebar. Per-article user tags filter the list down further."},{"icon":"🪶","title":"Single binary","details":"Pure-Go SQLite, embedded Svelte SPA, no CGO. A single ~25 MB binary that runs anywhere and behind any reverse proxy."},{"icon":"🎨","title":"8 themes + custom palette","details":"Auto (matches OS), Light, Dark, Solarized, Sepia, Nord, Gruvbox, High contrast, plus a custom theme that derives the rest of the palette from 3 colors you pick."},{"icon":"🔐","title":"Hardened by default","details":"argon2id passwords, SameSite=Strict cookies, CSRF double-submit, SSRF block on outbound fetches, generic error responses, govulncheck-clean stdlib."},{"icon":"⚖️","title":"Smart cross-feed dedup","details":"Tracking-param-stripped canonical URL + title-fingerprint clustering (48h window) collapse syndicated wire stories into one row. Click the \\"Also in N feeds\\" pill to expand the sibling list with per-feed read/star state."},{"icon":"🎯","title":"Rules engine","details":"Five actions (mark_read, star, hide, tag, add_to_board), eight match fields including feed, tags, published_at, has_image. Per-rule priority and a Preview button that counts last-7-day matches before you save."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1781028529000}`),n={name:"index.md"};function r(o,e,l,d,h,p){return t(),i("div",null,[...e[0]||(e[0]=[s(`<p>And plenty more under the hood: <strong>migrate your library</strong> (OPML subscriptions, or a full Tiny Tiny RSS migration — subscriptions, folders, and starred/archived articles), a <strong>Fever-compatible API</strong> (Reeder, FeedMe &amp; co. via a random per-user token), <strong>passkey sign-in</strong> (Touch ID / Face ID / hardware keys), an opt-in <strong>daily digest email</strong>, <strong>subscribe-by-URL</strong> discovery (including YouTube channels and Mastodon profiles), <strong>15-second auto-refresh</strong> with a favicon unread dot, and <strong>live admin controls</strong> for hot-swapping the LLM model, tuning generation params, and scheduling backups / cleanup / OPML exports.</p><h2 id="why" tabindex="-1">Why? <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why?&quot;">​</a></h2><p>Most RSS readers are either bloated cloud services that mine your reading habits, or unmaintained scripts from the Google Reader exodus. Ember is what an opinionated 2026 reader looks like: a single Go binary you run on your own box, a paper-and-ink interface, and — only if you want it — small-local-LLM summaries for the days you can&#39;t read 300 articles.</p><h2 id="quick-install" tabindex="-1">Quick install <a class="header-anchor" href="#quick-install" aria-label="Permalink to &quot;Quick install&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/brandonhon/ember.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ember/deploy</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set EMBER_SESSION_KEY and EMBER_ADMIN_PASSWORD</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Open <code>https://localhost</code>, log in, click a starter pack. You&#39;ll see articles within a minute.</p><p>See <a href="/ember/getting-started">Getting started</a> for details.</p>`,7)])])}const g=a(n,[["render",r]]);export{u as __pageData,g as default};
